#include<bits/stdc++.h>
using namespace std;
const int N=100005;
//tot->cnt
int n,m,k,a[N],block,id[N],cnt[200005];
long long sum,ans[N];
struct node
{
    int l,r,id;
} q[N];
bool cmp(node a,node b)
{
    if(id[a.l]==id[b.l]) return a.r<b.r;
    return  a.l<b.l;
}
void add(int x)
{
    sum+=cnt[a[x]^k];
    cnt[a[x]]++;
}
void del(int x)
{
    cnt[a[x]]--;
    sum-=cnt[a[x]^k];
}
int main()
{
    cin>>n>>m>>k;
    block=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i]=a[i]^a[i-1];
        id[i]=(i-1)/block+1;
    }
    for(int i=1;i<=m;i++)
    {
        cin>>q[i].l>>q[i].r;
        q[i].id=i;
    }
    sort(q+1,q+1+m,cmp);
    cnt[0]=1;
    int l=0,r=0;
    for(int i=1;i<=m;i++)
    {
        int tl=q[i].l-1,tr=q[i].r;
		while(l<tl) del(l++);
		while(l>tl) add(--l);
		while(r<tr) add(++r);
		while(r>tr) del(r--);
        ans[q[i].id]=sum;
    }
    for(int i=1;i<=m;i++)
    {
        cout<<ans[i]<<'\n';
    }
    return 0;
}
